import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { 
  ShoppingBag, 
  Search, 
  User, 
  Heart, 
  Menu,
  LogOut,
  LayoutDashboard
} from 'lucide-react';

const Navbar = () => {
  const { user, cartCount, logout } = useApp();
  const navigate = useNavigate();
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <nav className={`navbar ${isScrolled ? 'scrolled' : ''}`}>
      <div className="container nav-container">
        <Link to="/" className="nav-logo">
          <ShoppingBag size={28} strokeWidth={2.5} />
          <span>ShopSRY</span>
        </Link>

        <div className="nav-menu">
          <Link to="/" className="nav-link active">Bosh sahifa</Link>
          <Link to="/products" className="nav-link">Do'kon</Link>
          <Link to="/#categories" className="nav-link">Kategoriyalar</Link>
          <Link to="/#about" className="nav-link">Biz haqimizda</Link>
          <Link to="/#contact" className="nav-link">Bog'lanish</Link>
        </div>

        <div className="nav-actions">
          <div className="search-bar">
            <Search className="search-bar-icon" size={18} />
            <input type="text" placeholder="Qidirish..." />
          </div>

          <Link to="/wishlist" className="nav-btn">
            <Heart size={22} />
          </Link>

          <Link to="/cart" className="nav-btn">
            <ShoppingBag size={22} />
            {cartCount > 0 && <span className="badge">{cartCount}</span>}
          </Link>

          {user ? (
            <div className="user-profile" style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
              {user.role === 'admin' && (
                <Link to="/admin" className="nav-btn" title="Admin Panel">
                  <LayoutDashboard size={22} color="#2563EB" />
                </Link>
              )}
              <button onClick={handleLogout} className="nav-btn" title="Chiqish">
                <LogOut size={22} />
              </button>
            </div>
          ) : (
            <Link to="/login" className="nav-btn">
              <User size={22} />
            </Link>
          )}

          <button className="nav-btn mobile-menu" style={{ display: 'none' }}>
            <Menu size={24} />
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
